import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      {/* Popular Products Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                padding: "15px",
                background: "#fff",
                height: "200px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3
              className="product-name"
              style={{ fontSize: "15px", margin: "10px 0 5px" }}
            >
              {item.name}
            </h3>
            <p style={{ fontSize: "14px", color: "#555" }}>{item.description}</p>
            <p
              className="product-price"
              style={{ fontWeight: "bold", margin: "5px 0" }}
            >
              ${item.price}
            </p>
            <p style={{ fontSize: "14px", color: "#ff9800" }}>
              ⭐ {item.rating ? item.rating : "4.2"}
            </p>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#9d5b2e",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* Featured Picks Section */}
      <div style={{ marginTop: "60px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✨ Featured Picks
        </h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          {[
            {
              title: "Unparalleled Sound",
              desc: "Experience crystal-clear audio with premium headphones.",
              img: "/images/products/feature1.jpg",
            },
            {
              title: "Stay Connected",
              desc: "Compact and stylish earphones for every occasion.",
              img: "/images/products/feature3.jpg",
            },
            {
              title: "Power in Every Pixel",
              desc: "Shop the latest laptops for work, gaming, and more.",
              img: "/images/products/feature5.jpg",
            },
          ].map((card, index) => (
            <div
              key={index}
              style={{
                position: "relative",
                height: "370px",
                backgroundImage: `url(${card.img})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                display: "flex",
                alignItems: "flex-end",
                color: "#fff",
              }}
            >
              <div
                style={{
                  background: "rgba(0,0,0,0.6)",
                  padding: "15px",
                  width: "100%",
                }}
              >
                <h3 style={{ margin: "0 0 10px" }}>{card.title}</h3>
                <p style={{ fontSize: "14px", marginBottom: "10px" }}>
                  {card.desc}
                </p>
                <button
                  style={{
                    padding: "8px 15px",
                    border: "none",
                    background: "#9d5b2e",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  Buy Now ↗
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Promo Banner Section */}
      <div
        style={{
          marginTop: "60px",
          background: "#f3f4fc",
          padding: "50px 40px",
          borderRadius: "16px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          maxWidth: "1200px",
          marginLeft: "auto",
          marginRight: "auto",
        }}
      >
        {/* Left Product Image */}
        <img
          src="/images/products/jblspeaker.png"
          alt="Speaker"
          style={{ width: "220px", objectFit: "contain" }}
        />

        {/* Center Text Content */}
        <div style={{ textAlign: "center", flex: 1 }}>
          <h2
            style={{
              fontSize: "28px",
              fontWeight: "700",
              marginBottom: "10px",
              color: "#1f2937",
            }}
          >
            Level Up Your <br /> Gaming Experience
          </h2>
          <p
            style={{
              color: "#4b5563",
              fontSize: "16px",
              marginBottom: "20px",
            }}
          >
            From immersive sound to precise controls—everything you need to win
          </p>
          <button
            style={{
              padding: "12px 30px",
              border: "none",
              borderRadius: "6px",
              background: "#e4570e",
              color: "#fff",
              fontSize: "16px",
              fontWeight: "500",
              cursor: "pointer",
            }}
          >
            Buy now →
          </button>
        </div>

        {/* Right Product Image */}
        <img
          src="/images/products/xboxcontroller.png"
          alt="Controller"
          style={{ width: "220px", objectFit: "contain" }}
        />
      </div>

      {/* ✅ Subscribe Section */}
      <div
        style={{
          marginTop: "80px",
          padding: "50px 20px",
          background: "#f4f4f4",
          textAlign: "center",
        }}
      >
        <h2 style={{ marginBottom: "15px" }}>📩 Subscribe to Our Newsletter</h2>
        <p style={{ marginBottom: "20px", color: "#555" }}>
          Stay updated with the latest deals and new arrivals!
        </p>
        <form
          style={{
            display: "flex",
            justifyContent: "center",
            maxWidth: "500px",
            margin: "0 auto",
          }}
        >
          <input
            type="email"
            placeholder="Enter your email"
            required
            style={{
              padding: "12px",
              flex: 1,
              border: "1px solid #ccc",
              borderRadius: "6px 0 0 6px",
            }}
          />
          <button
            type="submit"
            style={{
              padding: "12px 20px",
              border: "none",
              background: "#9d5b2e",
              color: "#fff",
              borderRadius: "0 6px 6px 0",
              cursor: "pointer",
            }}
          >
            Subscribe
          </button>
        </form>
      </div>
    </section>
  );
};

export default PopularProducts;
